    <g font-family="sans-serif">
      <text x="20" y="55" fill="#a1a1aa" font-size="13" font-weight="700">① 価格の推移: 5万7,900ドル → 6万4,244ドル (+11%)</text>
      <line x1="60" y1="85" x2="640" y2="85" stroke="rgba(255,255,255,.15)" stroke-width="1" stroke-dasharray="4,4"/>
